/* Wrappers for streebog-512 to match sph_sha512 function pointer signature */
static void streebog512_init_wrap(void *ctx) {
    streebog_init((streebog_t *)ctx, 64);
}
static void streebog512_update_wrap(void *ctx, const void *data, size_t len) {
    streebog_update((streebog_t *)ctx, data, len);
}
static void streebog512_final_wrap(void *ctx, void *dest) {
    unsigned char tmp[64];
    streebog_final(tmp, (streebog_t *)ctx);
    /* Saarinen streebog.c outputs bytes in reverse order vs GOST standard;
       reverse to match the standard (and hashcat/adegtyarev convention) */
    unsigned char *d = (unsigned char *)dest;
    for (int i = 0; i < 64; i++) d[i] = tmp[63 - i];
}
/* All-in-one wrapper with standard byte order output */
static void gost2012_64_std(char *data, int len, unsigned char *dest) {
    unsigned char tmp[64];
    gost2012_64(data, len, tmp);
    for (int i = 0; i < 64; i++) dest[i] = tmp[63 - i];
}

