/* SM3 standalone implementation (GB/T 32905-2016) for crypt_round interface */
typedef struct {
    uint32_t h[8];
    uint8_t buf[64];
    uint64_t total;
} sm3_ctx;

#define SM3_ROTL32(x, n) (((x) << (n)) | ((x) >> (32 - (n))))
#define SM3_P0(x) ((x) ^ SM3_ROTL32((x), 9) ^ SM3_ROTL32((x), 17))
#define SM3_P1(x) ((x) ^ SM3_ROTL32((x), 15) ^ SM3_ROTL32((x), 23))

static const uint32_t sm3_T[64] = {
    0x79CC4519,0xF3988A32,0xE7311465,0xCE6228CB,0x9CC45197,0x3988A32F,0x7311465E,0xE6228CBC,
    0xCC451979,0x988A32F3,0x311465E7,0x6228CBCE,0xC451979C,0x88A32F39,0x11465E73,0x228CBCE6,
    0x9D8A7A87,0x3B14F50F,0x7629EA1E,0xEC53D43C,0xD8A7A879,0xB14F50F3,0x629EA1E7,0xC53D43CE,
    0x8A7A879D,0x14F50F3B,0x29EA1E76,0x53D43CEC,0xA7A879D8,0x4F50F3B1,0x9EA1E762,0x3D43CEC5,
    0x7A879D8A,0xF50F3B14,0xEA1E7629,0xD43CEC53,0xA879D8A7,0x50F3B14F,0xA1E7629E,0x43CEC53D,
    0x879D8A7A,0x0F3B14F5,0x1E7629EA,0x3CEC53D4,0x79D8A7A8,0xF3B14F50,0xE7629EA1,0xCEC53D43,
    0x9D8A7A87,0x3B14F50F,0x7629EA1E,0xEC53D43C,0xD8A7A879,0xB14F50F3,0x629EA1E7,0xC53D43CE,
    0x8A7A879D,0x14F50F3B,0x29EA1E76,0x53D43CEC,0xA7A879D8,0x4F50F3B1,0x9EA1E762,0x3D43CEC5
};

static void sm3_transform(sm3_ctx *ctx, const uint8_t block[64])
{
    uint32_t W[68], W2[64];
    int j;
    for (j = 0; j < 16; j++)
        W[j] = ((uint32_t)block[j*4]<<24) | ((uint32_t)block[j*4+1]<<16)
             | ((uint32_t)block[j*4+2]<<8) | block[j*4+3];
    for (j = 16; j < 68; j++)
        W[j] = SM3_P1(W[j-16] ^ W[j-9] ^ SM3_ROTL32(W[j-3], 15))
             ^ SM3_ROTL32(W[j-13], 7) ^ W[j-6];
    for (j = 0; j < 64; j++)
        W2[j] = W[j] ^ W[j+4];

    uint32_t a=ctx->h[0], b=ctx->h[1], c=ctx->h[2], d=ctx->h[3];
    uint32_t e=ctx->h[4], f=ctx->h[5], g=ctx->h[6], h=ctx->h[7];
    for (j = 0; j < 64; j++) {
        uint32_t a12 = SM3_ROTL32(a, 12);
        uint32_t ss1 = SM3_ROTL32(a12 + e + sm3_T[j], 7);
        uint32_t ss2 = ss1 ^ a12;
        uint32_t tt1, tt2;
        if (j < 16) {
            tt1 = (a ^ b ^ c) + d + ss2 + W2[j];
            tt2 = (e ^ f ^ g) + h + ss1 + W[j];
        } else {
            tt1 = (((a & b) | (c & (a ^ b)))) + d + ss2 + W2[j];
            tt2 = ((g ^ (e & (f ^ g)))) + h + ss1 + W[j];
        }
        d = c; c = SM3_ROTL32(b, 9); b = a; a = tt1;
        h = g; g = SM3_ROTL32(f, 19); f = e; e = SM3_P0(tt2);
    }
    ctx->h[0]^=a; ctx->h[1]^=b; ctx->h[2]^=c; ctx->h[3]^=d;
    ctx->h[4]^=e; ctx->h[5]^=f; ctx->h[6]^=g; ctx->h[7]^=h;
}

static void sm3_wrap_init(void *cc) {
    sm3_ctx *ctx = (sm3_ctx *)cc;
    ctx->h[0]=0x7380166f; ctx->h[1]=0x4914b2b9; ctx->h[2]=0x172442d7; ctx->h[3]=0xda8a0600;
    ctx->h[4]=0xa96f30bc; ctx->h[5]=0x163138aa; ctx->h[6]=0xe38dee4d; ctx->h[7]=0xb0fb0e4e;
    ctx->total = 0;
}

static void sm3_wrap_update(void *cc, const void *data, size_t len) {
    sm3_ctx *ctx = (sm3_ctx *)cc;
    const uint8_t *p = (const uint8_t *)data;
    size_t off = ctx->total & 63;
    ctx->total += len;
    if (off) {
        size_t n = 64 - off;
        if (len < n) { memcpy(ctx->buf + off, p, len); return; }
        memcpy(ctx->buf + off, p, n);
        sm3_transform(ctx, ctx->buf);
        p += n; len -= n;
    }
    while (len >= 64) { sm3_transform(ctx, p); p += 64; len -= 64; }
    if (len) memcpy(ctx->buf, p, len);
}

static void sm3_wrap_final(void *cc, void *out) {
    sm3_ctx *ctx = (sm3_ctx *)cc;
    uint64_t bits = ctx->total * 8;
    size_t off = ctx->total & 63;
    ctx->buf[off++] = 0x80;
    if (off > 56) {
        memset(ctx->buf + off, 0, 64 - off);
        sm3_transform(ctx, ctx->buf);
        off = 0;
    }
    memset(ctx->buf + off, 0, 56 - off);
    int j;
    for (j = 0; j < 8; j++) ctx->buf[56+j] = (uint8_t)(bits >> (56 - j*8));
    sm3_transform(ctx, ctx->buf);
    uint8_t *d = (uint8_t *)out;
    for (j = 0; j < 8; j++) {
        d[j*4]   = (uint8_t)(ctx->h[j]>>24);
        d[j*4+1] = (uint8_t)(ctx->h[j]>>16);
        d[j*4+2] = (uint8_t)(ctx->h[j]>>8);
        d[j*4+3] = (uint8_t)(ctx->h[j]);
    }
}

static void mysm3(char *data, int len, unsigned char *out) {
    sm3_ctx ctx;
    sm3_wrap_init(&ctx);
    sm3_wrap_update(&ctx, data, len);
    sm3_wrap_final(&ctx, out);
}

