static lock *Memlock;
unsigned long long memmax=0;
void *malloc_lock(size_t size, const char *reason)
{
  void *mem;
  possess(Memlock);
  mem = calloc(1,size);
  if (mem) memmax += size;
  release(Memlock);
  if (!mem) {
    fprintf(stderr,"Out of memory during %s\n",reason);
    exit(1);
  }
  return(mem);
}




