void current_utc_time(struct timespec *ts) {

#ifdef __MACH__ // OS X does not have clock_gettime, use clock_get_time
  clock_serv_t cclock;
  mach_timespec_t mts;
  host_get_clock_service(mach_host_self(), CALENDAR_CLOCK, &cclock);
  clock_get_time(cclock, &mts);
  mach_port_deallocate(mach_task_self(), cclock);
  ts->tv_sec = mts.tv_sec;
  ts->tv_nsec = mts.tv_nsec;
#else
  clock_gettime(CLOCK_REALTIME, ts);
#endif

}


void to_utf16le(char *src, char *dest, int len) {
    while (len--) {*dest++ = *src++; *dest++ = 0;}
}
  

char *memndup(void *source, int len) {
  char *dest = malloc_lock(len + 1,"memndup");
  if (!dest) {
    fprintf(stderr, "Out of memory in memndup\n");
    exit(1);
  }
  memmove(dest, source, len);
  return (dest);
}

void fastfillb(void *dest, void *src, int len) {
  unsigned int *d = (unsigned int *) dest;
  unsigned char *s = (unsigned char *) src;
  int l = (len / sizeof(unsigned int));
  unsigned int f;

  f = *s | (*s << 8) | (*s << 16) | (*s << 24);
  if ((l * sizeof(unsigned int)) != len)
    l++;

  while (l--)
    *d++ = f;
}

void fastfillw(void *dest, void *src, int len) {
  unsigned int *d = (unsigned int *) dest;
  unsigned short int *s = (unsigned short int *) src;
  int l = ((len * 2) / sizeof(unsigned int));
  unsigned int f;

  f = *s | (*s << 16);
  if ((l * sizeof(unsigned int)) != len * 2)
    l++;

  while (l--)
    *d++ = f;
}

void fastfilld(void *dest, void *src, int len) {
  unsigned int *d = (unsigned int *) dest;
  unsigned int *s = (unsigned int *) src;
  int l = len;
  unsigned int f;

  f = *s;

  while (l--)
    *d++ = f;
}

void fastmemmove(void *dest, void *src, int len) {
  unsigned long *d = (unsigned long *) dest;
  unsigned long *s = (unsigned long *) src;
  unsigned char *d1, *s1;
  int l = len / sizeof(unsigned long);
  len -= l * sizeof(unsigned long);
  while (l--)
    *d++ = *s++;
  d1 = (unsigned char *) d;
  s1 = (unsigned char *) s;
  while (len--)
    *d1++ = *s1++;
}

