inline void fastcopy(void *dest, void *src, int len) {
  unsigned long *d = (unsigned long *) dest;
  unsigned long *s = (unsigned long *) src;
  int l = (len + 1) / sizeof(unsigned long);
  if ((l * sizeof(unsigned long)) < len)
    l++;
  while (l--)
    *d++ = *s++;
}


