char phpitoa64[] = "./0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
char b64[]       = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

/* Encode 16-byte MD5 digest to 30-char Juniper NetScreen format.
 * Layout: 24 base64 data chars + 6 signature chars "nrcstn" at positions 0,6,12,17,23,29.
 * MD5 bytes treated as 4 big-endian 32-bit words, each split into upper/lower 16-bit halves,
 * each half producing 3 base64 chars from 6-bit chunks (bits 12,6,0). */
static void juniper_encode(const unsigned char *digest, char *out)
{
  int w, p = 0;
  static const char sig[] = "nrcstn";
  static const int sigpos[] = {0, 6, 12, 17, 23, 29};
  int si = 0;
  unsigned short hi, lo;
  char data[24];

  for (w = 0; w < 4; w++) {
    /* big-endian 32-bit word from little-endian MD5 bytes */
    hi = (digest[w*4+0] << 8) | digest[w*4+1]; /* upper 16 of BE word */
    lo = (digest[w*4+2] << 8) | digest[w*4+3]; /* lower 16 of BE word */
    data[w*6+0] = b64[(hi >> 12) & 0x3f];
    data[w*6+1] = b64[(hi >>  6) & 0x3f];
    data[w*6+2] = b64[(hi      ) & 0x3f];
    data[w*6+3] = b64[(lo >> 12) & 0x3f];
    data[w*6+4] = b64[(lo >>  6) & 0x3f];
    data[w*6+5] = b64[(lo      ) & 0x3f];
  }
  /* interleave signature chars */
  si = 0;
  { int di = 0;
    for (p = 0; p < 30; p++) {
      if (si < 6 && p == sigpos[si])
        out[p] = sig[si++];
      else
        out[p] = data[di++];
    }
  }
  out[30] = 0;
}

/* Encode 16-byte MD5 digest to 16-char Cisco PIX/ASA format.
 * Drops every 4th byte of MD5 digest, then encodes remaining 12 bytes
 * as 4 groups of 3 bytes using phpitoa64 (Unix crypt LSB-first encoding). */
static void cisco_pix_encode(const unsigned char *digest, char *out)
{
  int i, j = 0;
  for (i = 0; i < 16; i += 4) {
    unsigned int v = digest[i] | (digest[i+1] << 8) | (digest[i+2] << 16);
    out[j++] = phpitoa64[v & 0x3f];
    out[j++] = phpitoa64[(v >> 6) & 0x3f];
    out[j++] = phpitoa64[(v >> 12) & 0x3f];
    out[j++] = phpitoa64[(v >> 18) & 0x3f];
  }
  out[16] = 0;
}

/* AIX ssha* JudyJ[JOB_PKCS5S2] encoding: sequential bytes, big-endian pack, LSB-first extract */
static int aix_encode(const unsigned char *digest, int dlen, char *out) {
  int i, j = 0;
  for (i = 0; i + 2 < dlen; i += 3) {
    unsigned int v = ((unsigned int)digest[i] << 16) | (digest[i+1] << 8) | digest[i+2];
    out[j++] = phpitoa64[v & 0x3f]; v >>= 6;
    out[j++] = phpitoa64[v & 0x3f]; v >>= 6;
    out[j++] = phpitoa64[v & 0x3f]; v >>= 6;
    out[j++] = phpitoa64[v & 0x3f];
  }
  if (dlen - i == 2) {
    unsigned int v = ((unsigned int)digest[i] << 16) | (digest[i+1] << 8);
    out[j++] = phpitoa64[v & 0x3f]; v >>= 6;
    out[j++] = phpitoa64[v & 0x3f]; v >>= 6;
    out[j++] = phpitoa64[v & 0x3f];
  } else if (dlen - i == 1) {
    unsigned int v = (unsigned int)digest[i] << 16;
    out[j++] = phpitoa64[v & 0x3f]; v >>= 6;
    out[j++] = phpitoa64[v & 0x3f];
  }
  out[j] = 0;
  return j;
}

