/*
 *
 * findchr() is identical in purpose to strchr(3).  It's just
 * about 16 times faster.
 *
 */

#ifdef NOTINTEL
char *findchr(char *s, unsigned char c) {
    return(strchr(s,c));
}
#else

inline char *findchr(char *s, unsigned char c) {
  unsigned int align;
  unsigned int res, resz;
  __m128i cur, seek, zero;

  align = ((unsigned long long) s) & 0xf;
  seek = _mm_set1_epi8(c);
  zero = _mm_setzero_si128();
  s = (char *) (((unsigned long long) s) & 0xfffffffffffffff0);
  cur = _mm_load_si128((__m128i const *) s);
  resz = _mm_movemask_epi8(_mm_cmpeq_epi8(zero, cur)) >> align;
  res = (_mm_movemask_epi8(_mm_cmpeq_epi8(seek, cur)) >> align) & ~resz & (resz
                                                                           - 1);
  res <<= align;

  while (1) {
    if (res) return (s + ffs(res) - 1);
    if (resz) return NULL;
    s += 16;
    cur = _mm_load_si128((__m128i const *) s);
    resz = _mm_movemask_epi8(_mm_cmpeq_epi8(zero, cur));
    res = _mm_movemask_epi8(_mm_cmpeq_epi8(seek, cur)) & ~resz & (resz - 1);
  }
}

#endif

/*
 *
 * mystrlen is identical in function to strlen, but it can
 * read up to 3 bytes past the null.  Not an issue in this
 * code, as I know where all the buffers are, and there is ample
 * extra space at the end of each of them.
 *
 * This code would go faster if the pointers were aligned.
 *
 */

static size_t mystrlen(const void *v) {
  const unsigned int *s1;
  const unsigned char *s;
  unsigned int t;
  size_t len = 0;
  s1 = (unsigned int *) v;

  while ((t = *s1)) {
    if ((t - 0x01010101) & (~t) & 0x80808080)
      break;
    len += 4;
    s1++;
  }
  s = (unsigned char *) s1;
  while (*s++)
    len++;
  return (len);
}


char *mysql3(char *pass, int len, char *outbuf) {
  unsigned int nr, add, nr2, tmp;
  unsigned char ch;

  nr = 1345345333;
  nr2 = 0x12345671;
  add = 7;
  tmp = 0;
  for (; len; len--) {
    ch = *pass++;
    if (ch == ' ' || ch == '\t')
      continue;
    tmp = ch;
    nr ^= (((nr & 63) + add) * tmp) + ((nr << 8) & 0xffffffff);
    nr2 += ((nr2 << 8) & 0xffffffff) ^ nr;
    add += tmp;
  }
  sprintf(outbuf, "%08x%08x", nr & 0x7fffffff, nr2 & 0x7fffffff);
  return (outbuf);
}




static void gen_userid() {
  int x, y, tot, num;
  char *cur;

  if (Userid)
    return;
  tot = 6 * 10001 + 1000 * 4 + 9000 * 6;
  num = 0;

  Userid = malloc_lock(tot, "gen_userid");
  cur = Userid;
  for (x = 0; x < 999; x++) {
    y = sprintf(cur, "%d-", x);
    cur += y + 1;
    y = sprintf(cur, "%d", x);
    cur += y + 1;
    num += 2;
  }
  for (x = 1000; x < 10000; x++) {
    y = sprintf(cur, "%d-", x);
    cur += y + 1;
    y = sprintf(cur, "%d", x);
    cur += y + 1;
    num += 2;
  }
  *cur++ = 0;
  if ((cur - Userid) > tot) {
    fprintf(stderr, "Corrupted memory in gen-userid (%d,%ld)\n", tot, (cur - Userid));
    exit(1);
  }
  /* Also build UseridJudy from the same generated userids */
  { Word_t *UPV;
    char ubuf[16];
    for (x = 0; x < 999; x++) {
      sprintf(ubuf, "%d-", x);
      JSLI(UPV, UseridJudy, (unsigned char *)ubuf);
      if (UPV) *UPV = 1000000;
      sprintf(ubuf, "%d", x);
      JSLI(UPV, UseridJudy, (unsigned char *)ubuf);
      if (UPV) *UPV = 1000000;
    }
    for (x = 1000; x < 10000; x++) {
      sprintf(ubuf, "%d-", x);
      JSLI(UPV, UseridJudy, (unsigned char *)ubuf);
      if (UPV) *UPV = 1000000;
      sprintf(ubuf, "%d", x);
      JSLI(UPV, UseridJudy, (unsigned char *)ubuf);
      if (UPV) *UPV = 1000000;
    }
  }
  fprintf(stderr, "Generated %d Userids\n", num);
  Numsalts += num;
}

