static int geti64(char *iline, unsigned char *dest, int len) {
  unsigned char c, c1, c2, c3, c4, *line = (unsigned char *)iline;
  unsigned int cas;
  int cnt;

  cnt = 0;
  while ((cnt + 3) <= len && (c1 = i64hex[*line++]) < 64) {
    c2 = i64hex[*line++];
    c3 = i64hex[*line++];
    c4 = i64hex[*line++];
    cas = c1 | ((c2 & 0x3f) << 6) | ((c3 & 0x3f) << 12) | ((c4 & 0x3f) << 18);
    *dest++ = (cas & 0xff);
    cnt++;
    if (c2 > 63) {
      break;
    }
    *dest++ = (cas >> 8) & 0xff;
    cnt++;
    if (c3 > 63) {
      break;
    }
    *dest++ = (cas >> 16) & 0xff;
    cnt++;
    if (c4 > 63) {
      break;
    }
  }
  return (cnt);
}


