static int get32(char *iline, unsigned char *dest, int len) {
  unsigned char c1, c2, *line = (unsigned char *)iline;
  int cnt = 0;

#ifndef NOTINTEL
  /* Improved SSSE3: pshufb LUT nibble conversion + two-LUT Mula validation */
  const __m128i sub_lut = _mm_setr_epi8(
      0, 0, 0, 0x30, 0x37, 0, 0x57, 0,  0, 0, 0, 0, 0, 0, 0, 0);
  const __m128i hi_valid = _mm_setr_epi8(
      0, 0, 0, 1, 2, 0, 4, 0, 0, 0, 0, 0, 0, 0, 0, 0);
  const __m128i lo_valid = _mm_setr_epi8(
      1, 0x07, 0x07, 0x07, 0x07, 0x07, 0x07, 1, 1, 1, 0, 0, 0, 0, 0, 0);
  const __m128i lomask = _mm_set1_epi8(0x0F);
  const __m128i pack_hi = _mm_set1_epi16(0x00F0);
  const __m128i pack_lo = _mm_set1_epi16(0x0F00);
  const __m128i compact = _mm_setr_epi8(
      0, 2, 4, 6, 8, 10, 12, 14,  -1,-1,-1,-1,-1,-1,-1,-1);

  while (cnt + 8 <= len) {
      __m128i input = _mm_loadu_si128((const __m128i *)line);

      __m128i hi = _mm_and_si128(_mm_srli_epi16(input, 4), lomask);
      __m128i lo = _mm_and_si128(input, lomask);

      __m128i nibbles = _mm_sub_epi8(input, _mm_shuffle_epi8(sub_lut, hi));

      __m128i vcheck = _mm_and_si128(
          _mm_shuffle_epi8(hi_valid, hi),
          _mm_shuffle_epi8(lo_valid, lo));
      int inv_mask = _mm_movemask_epi8(
          _mm_cmpeq_epi8(vcheck, _mm_setzero_si128()));

      __m128i packed = _mm_or_si128(
          _mm_and_si128(_mm_slli_epi16(nibbles, 4), pack_hi),
          _mm_srli_epi16(_mm_and_si128(nibbles, pack_lo), 8));
      __m128i result = _mm_shuffle_epi8(packed, compact);

      if (inv_mask == 0) {
          _mm_storel_epi64((__m128i *)dest, result);
          cnt += 8; dest += 8; line += 16;
      } else {
          int valid_bytes = __builtin_ctz(inv_mask) / 2;
          uint64_t r;
          _mm_storel_epi64((__m128i *)&r, result);
          memcpy(dest, &r, valid_bytes);
          cnt += valid_bytes;
          dest += valid_bytes;
          line += valid_bytes * 2;
          break;
      }
  }
#endif /* !NOTINTEL */

#if defined(ARM) && defined(__aarch64__)
  /* AArch64 NEON: 128-bit, vqtbl1q_u8 (full pshufb equivalent)
   * Processes 16 hex chars → 8 output bytes per iteration */
  {
    const uint8x16_t sub_lut = {0,0,0,0x30,0x37,0,0x57,0, 0,0,0,0,0,0,0,0};
    const uint8x16_t hi_valid = {0,0,0,1,2,0,4,0, 0,0,0,0,0,0,0,0};
    const uint8x16_t lo_valid = {1,7,7,7,7,7,7,1, 1,1,0,0,0,0,0,0};
    const uint8x16_t lomask = vdupq_n_u8(0x0F);

    while (cnt + 8 <= len) {
      uint8x16_t input = vld1q_u8(line);
      uint8x16_t hi = vandq_u8(vshrq_n_u8(input, 4), lomask);
      uint8x16_t lo = vandq_u8(input, lomask);

      /* Validate: hi_valid[hi] & lo_valid[lo] must be nonzero for each byte */
      uint8x16_t vcheck = vandq_u8(vqtbl1q_u8(hi_valid, hi),
                                    vqtbl1q_u8(lo_valid, lo));
      /* Quick reject: OR all 16 bytes — if any is zero, we have invalid chars */
      uint8x16_t vzero = vceqq_u8(vcheck, vdupq_n_u8(0));
      uint64_t reject = vgetq_lane_u64(vreinterpretq_u64_u8(vzero), 0) |
                         vgetq_lane_u64(vreinterpretq_u64_u8(vzero), 1);

      /* Convert: subtract per-class offset to get 0-15 nibble values */
      uint8x16_t nibbles = vsubq_u8(input, vqtbl1q_u8(sub_lut, hi));

      /* Pack pairs of nibbles: high<<4 | low, then compact even bytes */
      uint8x16_t hi_nib = vshlq_n_u8(nibbles, 4);  /* odd positions (will be masked) */
      /* Reinterpret as 16-bit: each pair is [hi_char, lo_char] in memory (LE).
       * We want (hi_char_value << 4) | lo_char_value per 16-bit lane.
       * hi_nib has the shifted values in even bytes, nibbles has values in odd bytes.
       * Use VSRI to shift-right-insert: hi_nib[even] | nibbles[odd] >> 0 */
      /* Simpler: treat as u16 lanes, shift and OR */
      {
        uint16x8_t wide = vreinterpretq_u16_u8(nibbles);
        /* In LE memory: byte[0]=hi_char_nibble, byte[1]=lo_char_nibble per u16 lane.
         * Result byte = (byte[0] << 4) | byte[1] = ((u16 & 0x0F) << 4) | ((u16>>8) & 0x0F) */
        uint16x8_t packed = vorrq_u16(vshlq_n_u16(vandq_u16(wide, vdupq_n_u16(0x000F)), 4),
                                       vshrq_n_u16(wide, 8));
        /* packed: result byte in low byte of each u16 lane. Extract with UZP/TBL. */
        uint8x8x2_t uzp = vuzp_u8(vget_low_u8(vreinterpretq_u8_u16(packed)),
                                    vget_high_u8(vreinterpretq_u8_u16(packed)));
        /* uzp.val[0] has even-indexed bytes = our 8 result bytes */

        if (reject == 0) {
          vst1_u8(dest, uzp.val[0]);
          cnt += 8; dest += 8; line += 16;
        } else {
          /* Find first invalid pair: scan vzero for first nonzero byte */
          uint8_t vzbuf[16];
          int valid_bytes, k;
          vst1q_u8(vzbuf, vzero);
          valid_bytes = 0;
          for (k = 0; k < 16; k += 2) {
            if (vzbuf[k] || vzbuf[k+1]) break;
            valid_bytes++;
          }
          if (valid_bytes > 0) {
            uint8_t rbuf[8];
            vst1_u8(rbuf, uzp.val[0]);
            memcpy(dest, rbuf, valid_bytes);
            cnt += valid_bytes;
            dest += valid_bytes;
            line += valid_bytes * 2;
          }
          break;
        }
      }
    }
  }
#elif defined(ARM) && ARM >= 7
  /* ARM7/ARM8 32-bit NEON: 64-bit D-registers, vtbl2_u8 for table lookup
   * Processes 8 hex chars → 4 output bytes per iteration */
  if (Neon) {
    const uint8x8_t sub_lut_lo = {0,0,0,0x30,0x37,0,0x57,0};
    const uint8x8_t sub_lut_hi = {0,0,0,0,0,0,0,0};
    const uint8x8_t hi_valid_lo = {0,0,0,1,2,0,4,0};
    const uint8x8_t hi_valid_hi = {0,0,0,0,0,0,0,0};
    const uint8x8_t lo_valid_lo = {1,7,7,7,7,7,7,1};
    const uint8x8_t lo_valid_hi = {1,1,0,0,0,0,0,0};
    const uint8x8_t lomask = vdup_n_u8(0x0F);
    uint8x8x2_t sub_tbl = { {sub_lut_lo, sub_lut_hi} };
    uint8x8x2_t hiv_tbl = { {hi_valid_lo, hi_valid_hi} };
    uint8x8x2_t lov_tbl = { {lo_valid_lo, lo_valid_hi} };

    while (cnt + 4 <= len) {
      uint8x8_t input = vld1_u8(line);
      uint8x8_t hi = vand_u8(vshr_n_u8(input, 4), lomask);
      uint8x8_t lo = vand_u8(input, lomask);

      /* Validate */
      uint8x8_t vcheck = vand_u8(vtbl2_u8(hiv_tbl, hi), vtbl2_u8(lov_tbl, lo));
      uint64_t check64;
      vst1_u8((uint8_t *)&check64, vceq_u8(vcheck, vdup_n_u8(0)));

      /* Convert nibbles */
      uint8x8_t nibbles = vsub_u8(input, vtbl2_u8(sub_tbl, hi));

      /* Pack: treat as u16, combine pairs */
      {
        uint16x4_t wide = vreinterpret_u16_u8(nibbles);
        uint16x4_t packed = vorr_u16(vshl_n_u16(vand_u16(wide, vdup_n_u16(0x000F)), 4),
                                      vshr_n_u16(wide, 8));
        /* Result bytes in low byte of each u16. Extract bytes 0,2,4,6 → 0,1,2,3 */
        uint8x8_t pbytes = vreinterpret_u8_u16(packed);
        uint8_t rbuf[8];
        vst1_u8(rbuf, pbytes);

        if (check64 == 0) {
          dest[0] = rbuf[0]; dest[1] = rbuf[2];
          dest[2] = rbuf[4]; dest[3] = rbuf[6];
          cnt += 4; dest += 4; line += 8;
        } else {
          /* Find first invalid pair */
          uint8_t vzbuf[8];
          int valid_bytes = 0, k;
          vst1_u8(vzbuf, vceq_u8(vcheck, vdup_n_u8(0)));
          for (k = 0; k < 8; k += 2) {
            if (vzbuf[k] || vzbuf[k+1]) break;
            valid_bytes++;
          }
          for (k = 0; k < valid_bytes; k++)
            dest[k] = rbuf[k * 2];
          cnt += valid_bytes;
          dest += valid_bytes;
          line += valid_bytes * 2;
          break;
        }
      }
    }
  }
#endif /* ARM NEON */

  /* Scalar tail */
  while (cnt < len) {
     c1 = trhex[line[0]];
     c2 = trhex[line[1]];
     if (c1 > 15 || c2 > 15) break;
     *dest++ = (c1 << 4) | c2;
     line += 2;
     cnt++;
  }
  return (cnt);
}

#endif /* SMALL32 */


/*
 * commify will return a static pointer to a buffer containing
 * a null-terminated string, with a comma separting each group
 * of thousands.
 * For example, a supplied value of 123456789 will be returned
 * in a char * buffer like "123,456,789" with a null termination
 * ready for printing with %s.
 * You need to copy it, print it, or otherwise deal with it prior
 * to calling it again.  Not thread safe.
 */
static char Commify[128];

char *commify(unsigned long long source) {
  char temp[128];
  char *s, *d;
  int len, targlen, x;

  sprintf(temp, "%llu", source);
  len = mystrlen(temp);
  targlen = len + ((len - 1) / 3);
  d = &Commify[targlen];
  s = &temp[len];
  *d-- = *s--;
  for (x = 1; x <= len && d >= Commify; x++) {
    *d-- = *s--;
    if ((x % 3) == 0 && x && d >= Commify)
      *d-- = ',';
  }
  return (Commify);
}


static char hextab[16] = "0123456789abcdef";
static char hextabUC[16] = "0123456789ABCDEF";

char *prmd5REV(unsigned char *md5, char *out, int len) {
  char *ob;
  int x;
  unsigned char v;

  ob = out + len;
  *ob-- = 0;
  for (x = 0; x < len / 2; x++) {
    v = *md5++;
    *ob-- = hextab[(v >> 4) & 0xf];
    *ob-- = hextab[v & 0xf];
  }
  return (out);
}

char *prmd5(unsigned char *md5, char *out, int len) {
  char *ob;
  int x;
  unsigned char v;

  ob = out;
  for (x = 0; x < len / 2; x++) {
    v = *md5++;
    *ob++ = hextab[(v >> 4) & 0xf];
    *ob++ = hextab[v & 0xf];
  }
  *ob = 0;
  return (out);
}

char *prmd5UCREV(unsigned char *md5, char *out, int len) {
  char *ob;
  int x;
  unsigned char v;

  ob = out + len;
  *ob-- = 0;
  for (x = 0; x < len / 2; x++) {
    v = *md5++;
    *ob-- = hextabUC[(v >> 4) & 0xf];
    *ob-- = hextabUC[v & 0xf];
  }
  return (out);
}

char *prmd5UC(unsigned char *md5, char *out, int len) {
  char *ob;
  int x;
  unsigned char v;

  ob = out;
  for (x = 0; x < len / 2; x++) {
    v = *md5++;
    *ob++ = hextabUC[(v >> 4) & 0xf];
    *ob++ = hextabUC[v & 0xf];
  }
  *ob = 0;
  return (out);
}


#define MEMCHUNK ((sizeof(struct Hashchain)+7)*1000)
char *Mybuf;
int Mybufindex;


/*
 * mymalloc allocates a fixed-size, non-returnable space which
 * is aligned in memory according to the align value.
 * It allocates pre-zeroed memory, originally obtained from
 * calloc in MEMCHUNK-sized units.  It will always return
 * a valid memory pointer, and if there is not enough memory,
 * or the block is too large, will abend the program rather
 * than return a failure code.
 * Not thread safe - call from only the main program.
 */
void *mymalloc(int size, int align) {
  char *t;
  if ((Mybufindex % align) != 0) Mybufindex += align - (Mybufindex % align);
  if (Mybuf == NULL || (MEMCHUNK - Mybufindex) < (size + 2)) {
    Mybuf = malloc_lock(MEMCHUNK, "mymalloc");
    if (!Mybuf) {
      fprintf(stderr, "Out of memory in mymalloc\n");
      exit(1);
    }
    Mybufindex = 0;
  }
  if (Mybuf == NULL || (MEMCHUNK - Mybufindex) < (size + 2)) {
    fprintf(stderr, "mymalloc: You want too much space, %d bytes", size);
    exit(1);
  }
  t = &Mybuf[Mybufindex];
  Mybufindex += size;
  return (t);
}

