/* Atomic decrement of Judy PV refcount, with underflow guard */
#define PV_DEC(pv) { Word_t _old = *(pv); \
  while (_old > 0) { \
    if (__sync_bool_compare_and_swap((pv), _old, _old - 1)) break; \
    _old = *(pv); } }

