/* Mask-based hybrid attack support */
#define MAX_MASK_POS 16
#define MASK_LITERAL -1
#define MASK_CLASS_d 0
#define MASK_CLASS_l 1
#define MASK_CLASS_u 2
#define MASK_CLASS_s 3
#define MASK_CLASS_a 4
#define MASK_CLASS_b 5
#define MASK_CLASS_h 6
#define MASK_CLASS_H 7
#define MASK_CUSTOM_0 8
#define MASK_MAX_CLASSES 16

struct MaskClass { unsigned char chars[256]; int count; };
struct MaskPos   { int classid; unsigned char literal; };

struct MaskClass MaskClasses[MASK_MAX_CLASSES];
int              MaskNextCustom = MASK_CUSTOM_0;
struct MaskPos   MaskPattern[MAX_MASK_POS];
int              MaskLen;
int              MaskPrepend;
unsigned long long MaskTotal;
unsigned long long MaskChunkSize;

static void mask_init_classes(void) {
    int i;
    struct MaskClass *mc;
    /* ?d = digits 0-9 */
    mc = &MaskClasses[MASK_CLASS_d]; mc->count = 0;
    for (i = '0'; i <= '9'; i++) mc->chars[mc->count++] = i;
    /* ?l = lowercase a-z */
    mc = &MaskClasses[MASK_CLASS_l]; mc->count = 0;
    for (i = 'a'; i <= 'z'; i++) mc->chars[mc->count++] = i;
    /* ?u = uppercase A-Z */
    mc = &MaskClasses[MASK_CLASS_u]; mc->count = 0;
    for (i = 'A'; i <= 'Z'; i++) mc->chars[mc->count++] = i;
    /* ?s = specials (space + printable non-alnum) */
    mc = &MaskClasses[MASK_CLASS_s]; mc->count = 0;
    for (i = 0x20; i <= 0x7e; i++)
        if (!((i >= '0' && i <= '9') || (i >= 'a' && i <= 'z') || (i >= 'A' && i <= 'Z')))
            mc->chars[mc->count++] = i;
    /* ?a = all printable 0x20-0x7e */
    mc = &MaskClasses[MASK_CLASS_a]; mc->count = 0;
    for (i = 0x20; i <= 0x7e; i++) mc->chars[mc->count++] = i;
    /* ?b = all bytes 0x00-0xff */
    mc = &MaskClasses[MASK_CLASS_b]; mc->count = 0;
    for (i = 0; i <= 255; i++) mc->chars[mc->count++] = i;
    /* ?h = hex lowercase 0-9a-f */
    mc = &MaskClasses[MASK_CLASS_h]; mc->count = 0;
    for (i = '0'; i <= '9'; i++) mc->chars[mc->count++] = i;
    for (i = 'a'; i <= 'f'; i++) mc->chars[mc->count++] = i;
    /* ?H = hex uppercase 0-9A-F */
    mc = &MaskClasses[MASK_CLASS_H]; mc->count = 0;
    for (i = '0'; i <= '9'; i++) mc->chars[mc->count++] = i;
    for (i = 'A'; i <= 'F'; i++) mc->chars[mc->count++] = i;
}

static int hexval(int c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c >= 'a' && c <= 'f') return c - 'a' + 10;
    if (c >= 'A' && c <= 'F') return c - 'A' + 10;
    return 0;
}

/* Parse ?[...] character class, p points after '?['. Returns chars consumed from p. */
static int parse_char_class(const char *p, struct MaskClass *mc) {
    const char *start = p;
    unsigned char c, end;
    int i;
    mc->count = 0;
    while (*p && *p != ']') {
        if (*p == '\\') {
            p++;
            if (*p == 'x' && isxdigit((unsigned char)p[1]) && isxdigit((unsigned char)p[2])) {
                c = (hexval(p[1]) << 4) | hexval(p[2]);
                p += 3;
            } else if (*p >= '0' && *p <= '7') {
                c = *p++ - '0';
                if (*p >= '0' && *p <= '7') c = c * 8 + (*p++ - '0');
                if (*p >= '0' && *p <= '7') c = c * 8 + (*p++ - '0');
            } else {
                c = *p++;
            }
        } else {
            c = *p++;
        }
        if (*p == '-' && p[1] && p[1] != ']') {
            p++;
            if (*p == '\\') {
                p++;
                if (*p == 'x' && isxdigit((unsigned char)p[1]) && isxdigit((unsigned char)p[2])) {
                    end = (hexval(p[1]) << 4) | hexval(p[2]);
                    p += 3;
                } else if (*p >= '0' && *p <= '7') {
                    end = *p++ - '0';
                    if (*p >= '0' && *p <= '7') end = end * 8 + (*p++ - '0');
                    if (*p >= '0' && *p <= '7') end = end * 8 + (*p++ - '0');
                } else {
                    end = *p++;
                }
            } else {
                end = *p++;
            }
            for (i = c; i <= (int)end; i++)
                if (mc->count < 256) mc->chars[mc->count++] = i;
        } else {
            if (mc->count < 256) mc->chars[mc->count++] = c;
        }
    }
    if (*p == ']') p++;
    return (int)(p - start);
}

/* Parse mask string into MaskPattern[]. Returns 0 on success, -1 on error. */
static int parse_mask(const char *s) {
    MaskLen = 0;
    MaskTotal = 1;
    while (*s && MaskLen < MAX_MASK_POS) {
        if (*s == '?') {
            s++;
            int classid = -1;
            switch (*s) {
                case 'd': classid = MASK_CLASS_d; s++; break;
                case 'l': classid = MASK_CLASS_l; s++; break;
                case 'u': classid = MASK_CLASS_u; s++; break;
                case 's': classid = MASK_CLASS_s; s++; break;
                case 'a': classid = MASK_CLASS_a; s++; break;
                case 'b': classid = MASK_CLASS_b; s++; break;
                case 'h': classid = MASK_CLASS_h; s++; break;
                case 'H': classid = MASK_CLASS_H; s++; break;
                case '?': /* literal ? */
                    MaskPattern[MaskLen].classid = MASK_LITERAL;
                    MaskPattern[MaskLen].literal = '?';
                    MaskLen++;
                    s++;
                    continue;
                case '[': /* custom class */
                    s++;
                    if (MaskNextCustom >= MASK_MAX_CLASSES) {
                        fprintf(stderr, "Too many custom character classes\n");
                        return -1;
                    }
                    classid = MaskNextCustom++;
                    s += parse_char_class(s, &MaskClasses[classid]);
                    if (MaskClasses[classid].count == 0) {
                        fprintf(stderr, "Empty character class\n");
                        return -1;
                    }
                    break;
                default:
                    fprintf(stderr, "Unknown mask class ?%c\n", *s);
                    return -1;
            }
            MaskPattern[MaskLen].classid = classid;
            MaskTotal *= MaskClasses[classid].count;
        } else {
            MaskPattern[MaskLen].classid = MASK_LITERAL;
            MaskPattern[MaskLen].literal = *s++;
        }
        MaskLen++;
    }
    if (MaskLen == 0) {
        fprintf(stderr, "Empty mask pattern\n");
        return -1;
    }
    return 0;
}

static inline int mask_expand(unsigned long long index, char *buf) {
    int i;
    for (i = MaskLen - 1; i >= 0; i--) {
        if (MaskPattern[i].classid == MASK_LITERAL)
            buf[i] = MaskPattern[i].literal;
        else {
            struct MaskClass *mc = &MaskClasses[MaskPattern[i].classid];
            buf[i] = mc->chars[index % mc->count];
            index /= mc->count;
        }
    }
    return MaskLen;
}

