/* compact_resize: rebuild compact table at double the current size.
 * Re-inserts all HashData entries; overflow entries that now fit are reclaimed. */
static void compact_resize(void) {
    uint64_t old_size = CompactSize;
    uint64_t new_size = CompactSize * 2;
    uint64_t new_mask = new_size - 1;
    uint32_t *new_fp, *new_idx;
    size_t i;
    uint32_t new_overflow = 0;
    Pvoid_t new_ovh = NULL;

    fprintf(stderr, "Compact hash table: growing from %llu to %llu slots\n",
           (unsigned long long)old_size, (unsigned long long)new_size);

    new_fp = calloc(new_size, sizeof(uint32_t));
    new_idx = malloc(new_size * sizeof(uint32_t));
    if (!new_fp || !new_idx) {
        fprintf(stderr, "Failed to resize compact table to %llu slots\n",
                (unsigned long long)new_size);
        exit(1);
    }

    /* Free old overflow chains */
    if (OverflowHash) {
        Word_t okey = 0;
        Word_t *PV;
        JLF(PV, OverflowHash, okey);
        while (PV) {
            struct Hashchain *ch = (struct Hashchain *)(*PV);
            while (ch) {
                struct Hashchain *nx = ch->next;
                free(ch);
                ch = nx;
            }
            JLN(PV, OverflowHash, okey);
        }
        Word_t freed;
        JLFA(freed, OverflowHash);
    }

    free(CompactFP);
    free(CompactIdx);
    CompactFP = new_fp;
    CompactIdx = new_idx;
    CompactSize = new_size;
    CompactMask = new_mask;
    CompactUsed = 0;
    OverflowHash = new_ovh;

    /* Re-insert all entries */
    for (i = 0; i < HashDataCount; i++) {
        unsigned char *hash = HashDataBuf + HashDataOff[i];
        int hlen = HashDataLen[i];
        uint64_t key = *(uint64_t *)hash;
        uint32_t fp = (uint32_t)(key >> 32);
        uint64_t pos = compact_mix(key) & new_mask;
        int p;

        if (!fp) fp = 1;

        for (p = 0; p < COMPACT_MAX_PROBE; p++) {
            if (!CompactFP[pos]) {
                CompactFP[pos] = fp;
                CompactIdx[pos] = (uint32_t)i;
                CompactUsed++;
                goto resized;
            }
            pos = (pos + 1) & new_mask;
        }

        /* Still overflows at new size — add to overflow */
        {
            Word_t *PV2;
            struct Hashchain *chain, *next, *prev;
            JLI(PV2, OverflowHash, (Word_t)key);
            next = (struct Hashchain *)(*PV2);
            prev = NULL;
            while (next) {
                if (hlen < next->len) break;
                if (memcmp(hash + 8, next->hash, hlen - 8) <= 0) break;
                prev = next;
                next = next->next;
            }
            chain = malloc(sizeof(struct Hashchain) + hlen - 9);
            chain->len = hlen;
            chain->flags = HashDataFlags[i];
            memmove(chain->hash, hash + 8, hlen - 8);
            chain->next = next;
            if (!prev) *PV2 = (Word_t)chain;
            else prev->next = chain;
            new_overflow++;
        }
        resized: ;
    }
}

/* compact_insert: insert entry at HashDataCount into compact table.
 * Returns 0 if inserted (new), 1 if duplicate. Triggers resize at 50% load. */
static int compact_insert(void) {
    size_t data_idx = HashDataCount;
    unsigned char *hash = HashDataBuf + HashDataOff[data_idx];
    int hlen = HashDataLen[data_idx];
    uint64_t key = *(uint64_t *)hash;
    uint32_t fp = (uint32_t)(key >> 32);
    uint64_t pos;
    int p;

    if (!fp) fp = 1;

    /* Resize at 50% load */
    if (CompactUsed * 2 >= CompactSize) {
        compact_resize();
    }

    pos = compact_mix(key) & CompactMask;

    for (p = 0; p < COMPACT_MAX_PROBE; p++) {
        if (!CompactFP[pos]) {
            CompactFP[pos] = fp;
            CompactIdx[pos] = (uint32_t)data_idx;
            CompactUsed++;
            return 0;
        }
        if (CompactFP[pos] == fp) {
            size_t eidx = CompactIdx[pos];
            int elen = HashDataLen[eidx];
            if (elen == hlen && memcmp(hash, HashDataBuf + HashDataOff[eidx], hlen) == 0) {
                return 1;  /* duplicate */
            }
        }
        pos = (pos + 1) & CompactMask;
    }

    /* MAX_PROBE exhausted — check overflow for dup, else add */
    {
        Word_t *PV;
        struct Hashchain *chain, *next, *prev;

        JLI(PV, OverflowHash, (Word_t)key);
        next = (struct Hashchain *)(*PV);
        prev = NULL;

        while (next) {
            if (hlen < next->len) break;
            if (memcmp(hash + 8, next->hash, hlen - 8) <= 0) break;
            prev = next;
            next = next->next;
        }
        if (next && next->len == hlen &&
            memcmp(hash + 8, next->hash, hlen - 8) == 0) {
            return 1;  /* duplicate in overflow */
        }

        chain = malloc(sizeof(struct Hashchain) + hlen - 9);
        chain->len = hlen;
        chain->flags = 0;
        memmove(chain->hash, hash + 8, hlen - 8);
        chain->next = next;
        if (!prev) *PV = (Word_t)chain;
        else prev->next = chain;
    }
    return 0;
}

static void gen_salts() {
  int x, y, z, num, tot,  Dosalt[JOB_DONE];
  int Dosaltcnt=0;
  char *cur,any=0;
  unsigned char line[MAXLINE + 16];
  Word_t *PV, RC, ti;
  Pvoid_t lsalt = NULL;

  ti = 0;
  J1F(RC, Dohash, ti);
  while (RC) {
    if (ti < JOB_DONE) {
      if ((TypeOpts[ti] & TYPEOPT_NEEDSALT) && !(TypeOpts[ti] & TYPEOPT_NEEDSJ) && !Typesalt[ti]) {
	Dosalt[Dosaltcnt++] = ti;
        any = 1;
      }
    }
    J1N(RC, Dohash, ti);
  }
  if (!any) return;

  tot = 5 * (96 * 96 * 96) + 4 * (96 * 96) + 6 * (10001);
  num = 0;

  for (x = ' '; x < 128; x++) {
    for (y = ' '; y < 128; y++) {
      line[0]=x;line[1]=y;line[2]=0;
      JSLI(PV,lsalt,line);
      if (PV) *PV = 1000000;
      num++;
    }
  }
  for (x = ' '; x < 128; x++) {
    for (y = ' '; y < 128; y++) {
      for (z = ' '; z < 128; z++) {
	line[0]=x;line[1]=y;line[2]=z;line[3]=0;
	JSLI(PV,lsalt,line);
	if (PV) *PV = 1000000;
        num++;
      }
    }
  }
  for (x = 0; x < 1000; x++) {
    sprintf((char *)line, "%d-", x);
    JSLI(PV,lsalt,line);
    if (PV) *PV = 1000000;
    num++;
  }
  for (x = 1000; x < 10000; x++) {
    sprintf((char *)line, "%d", x);
    JSLI(PV,lsalt,line);
    if (PV) *PV = 1000000;
    num++;
  }
  fprintf(stderr, "Generated %d salts\n", num);
  for (x=0; x <Dosaltcnt; x++) {
    fprintf(stderr,"Added to %s salts\n",Types[Dosalt[x]]);
    Typesalt[Dosalt[x]] = lsalt;
  }
  Numsalts += num;
}
