int checkhashsalt2(union HashU *curin, int len,
    char *salt1, int salt1len,
    char *salt2, int salt2len,
    int x, struct job *job) {
  int match_len;
  unsigned short *match_flags;
  int hfound = hybrid_check(curin->h, len, &match_len, &match_flags);
  struct Hashchain found;
  char newbuf2[513];
  char saltbuf1[MAXLINE * 2], saltbuf2[MAXLINE * 2];
  int j, dohex;
  int hitcount = 0;

  if (job->clen > MAXLINE) {
    fprintf(stderr,"Output line too long: %d bytes in type %s\n",job->clen,Types[job->op]);
    exit(1);
  }
  if (Printall && !hfound) {
    found.flags = 0;
    match_flags = &found.flags;
    match_len = len / 2;
    hfound = 1;
  }
  if (hfound && *match_flags != (unsigned short)job->op) {
    hitcount++;
    *match_flags = job->op;
    prmd5(curin->h, newbuf2, match_len * 2);
    /* encode salt1 */
    saltbuf1[salt1len] = 0;
    for (j = 0; j < salt1len; j++) {
      saltbuf1[j] = salt1[j];
      if ((signed char) (salt1[j]+1) < '!') {
        strcpy(saltbuf1, "$HEX[");
        for (j = 0; j < salt1len; j++)
          sprintf(&saltbuf1[2 * j + 5], "%02x", salt1[j] & 0xff);
        saltbuf1[2 * j + 5] = ']';
        saltbuf1[2 * j + 6] = 0;
        break;
      }
    }
    /* encode salt2 */
    saltbuf2[salt2len] = 0;
    for (j = 0; j < salt2len; j++) {
      saltbuf2[j] = salt2[j];
      if ((signed char) (salt2[j]+1) < '!') {
        strcpy(saltbuf2, "$HEX[");
        for (j = 0; j < salt2len; j++)
          sprintf(&saltbuf2[2 * j + 5], "%02x", salt2[j] & 0xff);
        saltbuf2[2 * j + 5] = ']';
        saltbuf2[2 * j + 6] = 0;
        break;
      }
    }
    job->pass[job->clen] = 0;
    for (dohex = j = 0; j < job->clen; j++) {
      if ((signed char) (job->pass[j]+1) < '!' || job->pass[j] == ':') {
        dohex = 1;
        break;
      }
    }
    if (job->clen > 5 && strncmp(job->pass, "$HEX[", 5) == 0)
      dohex = 1;
#if ARM < 8
possess(FreeWaiting);
#endif
    if (RuleCnt)
      atomic_fetch_add(&RuleCnt[job->Ruleindex],1);
    atomic_fetch_add(&Totalfound[job->op - 1][x > 0 ? x - 1 : 0],1);
#if ARM < 8
release(FreeWaiting);
#endif
    (*job->found)++;
    if ((job->flags & JOBFLAG_PRINT) && *job->doneprint == 0) {
      printf("# From %s\n", job->filename);fflush(stdout);
      *job->doneprint = 1;
    }
    if (job->outlen && ((job->outlen + job->clen*2) > OUTBUFSIZE)) {
      fwrite(job->outbuf,job->outlen,1,stdout);fflush(stdout);
      job->outlen = 0;
    }
    if (dohex) {
      if (x > 0)
        job->outlen += sprintf(&job->outbuf[job->outlen],"%sx%02d %s:%s:%s:$HEX[", Types[job->op], x, newbuf2, saltbuf1, saltbuf2);
      else
        job->outlen += sprintf(&job->outbuf[job->outlen],"%s %s:%s:%s:$HEX[", Types[job->op], newbuf2, saltbuf1, saltbuf2);
      prmd5((unsigned char *)job->pass, &job->outbuf[job->outlen], job->clen*2);
      job->outlen += job->clen*2;
      job->outbuf[job->outlen++] = ']';
      job->outbuf[job->outlen++] = '\n';
    } else {
      if (x > 0)
        job->outlen += sprintf(&job->outbuf[job->outlen],"%sx%02d %s:%s:%s:%s\n", Types[job->op], x, newbuf2, saltbuf1, saltbuf2, job->pass);
      else
        job->outlen += sprintf(&job->outbuf[job->outlen],"%s %s:%s:%s:%s\n", Types[job->op], newbuf2, saltbuf1, saltbuf2, job->pass);
    }
  }
  return (hitcount);
}

int checkhashbb(union HashU *curin, int len, char *salt, struct job *job) {
  Word_t RC;
  Word_t *PV, tr1, tr2;
  unsigned char *t;
  int i, j, offset, rotval, dohex, ret, hlen, bit, index;
  unsigned int cas;
  char newbuf[513];
  union HashU *Origin, check, test;
  struct Hashchain *next, found;
  int hitcount = 0;

  if (job->clen > MAXLINE) {
    fprintf(stderr,"Output line too long: %d bytes in type %s\n",job->clen,Types[job->op]);
    fprintf(stderr,"Password: %s\n",job->pass);
    exit(1);
  }
  {
    int match_len;
    unsigned short *match_flags;
    int hfound = hybrid_check(curin->h, len, &match_len, &match_flags);
    if (Printall && !hfound) {
      found.flags = 0;
      match_flags = &found.flags;
      hfound = 1;
    }
    if (hfound && *match_flags != (unsigned short)job->op) {
      hitcount++;
      *match_flags = job->op;

      len /= 2;
      curin->h[len] = 0;
      for (i = j = 0; j < len;) {
        cas = curin->h[j] | (curin->h[j + 1] << 8) | (curin->h[j + 2] << 16);
        newbuf[i++] = phpitoa64[cas & 0x3f];
        cas >>= 6;
        newbuf[i++] = phpitoa64[cas & 0x3f];
        cas >>= 6;
        j++;
        if (j >= len)
          break;
        newbuf[i++] = phpitoa64[cas & 0x3f];
        cas >>= 6;
        j++;
        if (j >= len)
          break;
        newbuf[i++] = phpitoa64[cas & 0x3f];
        cas >>= 6;
        j++;
      }
      newbuf[i] = 0;

      job->pass[job->clen] = 0;
      for (dohex = j = 0; j < job->clen; j++) {
        if ((signed char) (job->pass[j]+1) < '!' || job->pass[j] == ':') {
          dohex = 1;
          break;
        }
      }
      if (job->clen > 5 && strncmp(job->pass, "$HEX[", 5) == 0)
        dohex = 1;
#if ARM < 8
possess(FreeWaiting);
#endif
      if (RuleCnt) atomic_fetch_add(&RuleCnt[job->Ruleindex],1);
      atomic_fetch_add(&Totalfound[job->op - 1][0],1);
#if ARM < 8
release(FreeWaiting);
#endif
      (*job->found)++;
      if ((job->flags & JOBFLAG_PRINT) && *job->doneprint == 0) {
        printf("# From %s\n", job->filename);fflush(stdout);
        *job->doneprint = 1;
      }
      if (job->outlen && ((job->outlen + job->clen*2) > OUTBUFSIZE)) {
	fwrite(job->outbuf,job->outlen,1,stdout);fflush(stdout);
	job->outlen = 0;
      }
      if (dohex) {
	job->outlen += sprintf(&job->outbuf[job->outlen],"%s %s%s:$HEX[", Types[job->op], salt, newbuf);
	prmd5((unsigned char *)job->pass, &job->outbuf[job->outlen], job->clen*2);
	job->outlen += job->clen*2;
	job->outbuf[job->outlen++] = ']';
	job->outbuf[job->outlen++] = '\n';
      } else
	job->outlen += sprintf(&job->outbuf[job->outlen],"%s %s%s:%s\n", Types[job->op], salt, newbuf, job->pass);
    }
  }
  return (hitcount);
}

void prfound(struct job *job, char *hash) {
  int dohex, j;

  job->pass[job->clen] = 0;
  for (dohex = j = 0; j < job->clen; j++) {
    if ((signed char) (job->pass[j]+1) < '!' || job->pass[j] == ':') {
      dohex = 1;
      break;
    }
  }
  if (job->clen > 5 && strncmp(job->pass, "$HEX[", 5) == 0)
    dohex = 1;
#if ARM < 8
possess(FreeWaiting);
#endif
  if (RuleCnt)
    atomic_fetch_add(&RuleCnt[job->Ruleindex],1);
  atomic_fetch_add(&Totalfound[job->op - 1][0],1);
#if ARM < 8
release(FreeWaiting);
#endif
  (*job->found)++;
  if ((job->flags & JOBFLAG_PRINT) && *job->doneprint == 0) {
    printf("# From %s\n", job->filename);fflush(stdout);
    *job->doneprint = 1;
  }
  if (job->outlen && ((job->outlen + job->clen*2) > OUTBUFSIZE)) {
    fwrite(job->outbuf,job->outlen,1,stdout);fflush(stdout);
    job->outlen = 0;
  }
  if (dohex) {
    job->outlen += sprintf(&job->outbuf[job->outlen],"%s %s:$HEX[", Types[job->op], hash);
    prmd5((unsigned char *)job->pass, &job->outbuf[job->outlen], job->clen*2);
    job->outlen += job->clen*2;
    job->outbuf[job->outlen++] = ']';
    job->outbuf[job->outlen++] = '\n';
  } else
    job->outlen += sprintf(&job->outbuf[job->outlen],"%s %s:%s\n", Types[job->op], hash, job->pass);
}

static int build_salt_snapshot(struct saltentry *snap, char *pool,
                               Pvoid_t judy, char *keybuf, int printall) {
    Word_t *lpv;
    int n = 0;
    char *p = pool;
    keybuf[0] = 0;
    JSLF(lpv, judy, (unsigned char *)keybuf);
    while (lpv) {
        if (printall || *lpv > 0) {
            int slen = mystrlen(keybuf);
            memcpy(p, keybuf, slen + 1);
            snap[n].salt = p;
            snap[n].PV = lpv;
            snap[n].saltlen = slen;
            p += slen + 1;
            n++;
        }
        JSLN(lpv, judy, (unsigned char *)keybuf);
    }
    return n;
}

