                  unsigned char *u16p = (unsigned char *)wline;
                  unsigned char ntlmhash[16];
                  for (y = 0; y < len; y++) { u16p[y*2] = cur[y]; u16p[y*2+1] = 0; }
                  MD4((char *)u16p, len * 2, ntlmhash);

