                  char *sl = saltsnap[si].salt;
                  char *sc1 = strchr(sl, ':');
                  if (!sc1) continue;
                  char *sc2 = strchr(sc1 + 1, ':');
                  if (!sc2) continue;
                  int iters = atoi(sl);
                  if (iters < 1) continue;
                  int emaillen = sc2 - sc1 - 1;
                  char *email = sc1 + 1;
                  char *ivhex = sc2 + 1;
                  if ((int)strlen(ivhex) != 32) continue;

