                  unsigned char *rk_pbsalt  = (unsigned char *)newbuf + 256;
                  unsigned char *rk_stmp    = (unsigned char *)newbuf + 384;
                  DES_key_schedule *rk_ks   = (DES_key_schedule *)linebuf;
