                    const char *ts = saltsnap[si].salt;
                    const char *star1 = strchr(ts, '*');
                    if (!star1) continue;
                    int ulen = star1 - ts;
                    if (ulen < 1 || ulen > 8) continue;
                    const char *star2 = strchr(star1 + 1, '*');
                    if (!star2 || (star2 - star1 - 1) != 32) continue;
                    int salthex_len = saltsnap[si].saltlen - (star2 + 1 - ts);
