                      rk_stmp[rk_slen+2] = 0; rk_stmp[rk_slen+3] = 1;
                      HMAC(EVP_sha256(), rk_key, 8, rk_stmp, rk_slen + 4, rk_U, &hmlen);
                      memcpy(rk_out, rk_U, 32);
