                      memcpy(rk_fs, rk_membuf, final_slen);
                      rk_fs[final_slen] = 0; rk_fs[final_slen+1] = 0;
                      rk_fs[final_slen+2] = 0; rk_fs[final_slen+3] = 1;
                      HMAC(EVP_sha256(), rk_key, 32, rk_fs, final_slen + 4, rk_U, &hmlen);
