                        /* A XOR t (big-endian, t fits in low bytes) */
                        A[7] ^= (t & 0xff);
                        A[6] ^= ((t >> 8) & 0xff);
                        /* Concatenate A || R[ii] and decrypt */
                        unsigned char B[16];
                        memcpy(B, A, 8);
                        memcpy(B + 8, R[ii], 8);
                        AES_ecb_encrypt(B, B, an_aeskey, AES_DECRYPT);
