                    char *jwt = saltsnap[si].salt;
                    int jwt_len = saltsnap[si].saltlen;
                    /* Find last dot to split header.payload from signature */
                    char *last_dot = NULL;
                    for (x = jwt_len - 1; x >= 0; x--) {
                      if (jwt[x] == '.') { last_dot = jwt + x; break; }
                    }
