                        *PV2 = 1;
                        PV_DEC(saltsnap[si].PV);
                        if (*saltsnap[si].PV == 0) {
                          saltsnap[si] = saltsnap[--nsalts_job]; si--;
                        }
                      prfound(job, linebuf2);
