                      bp[0] = '-'; bp[1] = '-'; bp += 2;
                      memmove(bp, combined, saltlen); bp += saltlen;
                      bp[0] = '-'; bp[1] = '-'; bp += 2;
                      fastcopy(bp, cur, len); bp += len;
                      bp[0] = '-'; bp[1] = '-'; bp += 2;
                      memmove(bp, p1, peplen); bp += peplen;
