                      snprintf(linebuf2, MAXLINE, "$ansible$0*0*%.*s*%s*%s",
                               64, ts, ct_start, mdbuf);
                      if (!Printall) {
                        *PV2 = 1;
                        PV_DEC(saltsnap[si].PV);
                        if (*saltsnap[si].PV == 0) {
                          saltsnap[si] = saltsnap[--nsalts_job]; si--;
                        }
                      }
                      prfound(job, linebuf2);
